COPY public.lexique (id, terme, definition, categorie) FROM stdin;
7	adaptogène	Se dit d'une plante qui aide l'organisme à mieux résister au stress physique et mental en rééquilibrant les fonctions biologiques.	propriete
8	adoucissante	Apaise et protège les muqueuses et la peau irritées en formant un film protecteur.	propriete
